.create table ManagedDevices (DeviceId: string, DeviceName: string, UserId: string, UserPrincipalName: string, UserDisplayName: string, OperatingSystem: string, OSVersion: string, ComplianceState: string, ManagementAgent: string, EnrolledDateTime: datetime, LastSyncDateTime: datetime, Model: string, Manufacturer: string, SerialNumber: string, IsEncrypted: bool, IsSupervised: bool, AzureADDeviceId: string, IngestionTime: datetime, SourceSystem: string)

.alter table ManagedDevices policy retention ```{ "SoftDeletePeriod": "7.00:00:00", "Recoverability": "Disabled" }```

.create materialized-view ManagedDevices_Current on table ManagedDevices { ManagedDevices | summarize arg_max(IngestionTime, *) by DeviceId }

.create table CompliancePolicies (PolicyId: string, PolicyName: string, Description: string, CreatedDateTime: datetime, LastModifiedDateTime: datetime, PolicyType: string, IngestionTime: datetime, SourceSystem: string)

.alter table CompliancePolicies policy retention ```{ "SoftDeletePeriod": "7.00:00:00", "Recoverability": "Disabled" }```

.create materialized-view CompliancePolicies_Current on table CompliancePolicies { CompliancePolicies | summarize arg_max(IngestionTime, *) by PolicyId }

.create table DeviceComplianceStates (DeviceId: string, DeviceName: string, UserId: string, UserPrincipalName: string, PolicyId: string, PolicyName: string, Status: string, StatusRaw: int, SettingCount: int, FailedSettingCount: int, LastContact: datetime, InGracePeriodCount: int, IngestionTime: datetime, SourceSystem: string)

.alter table DeviceComplianceStates policy retention ```{ "SoftDeletePeriod": "7.00:00:00", "Recoverability": "Disabled" }```

.create materialized-view DeviceComplianceStates_Current on table DeviceComplianceStates { DeviceComplianceStates | summarize arg_max(IngestionTime, *) by DeviceId, PolicyId }

.create table DeviceScores (DeviceId: string, DeviceName: string, Model: string, Manufacturer: string, HealthStatus: string, EndpointAnalyticsScore: real, StartupPerformanceScore: real, AppReliabilityScore: real, WorkFromAnywhereScore: real, MeanResourceSpikeTimeScore: real, BatteryHealthScore: real, IngestionTime: datetime, SourceSystem: string)

.alter table DeviceScores policy retention ```{ "SoftDeletePeriod": "7.00:00:00", "Recoverability": "Disabled" }```

.create materialized-view DeviceScores_Current on table DeviceScores { DeviceScores | summarize arg_max(IngestionTime, *) by DeviceId }

.create table StartupPerformance (DeviceId: string, StartTime: datetime, CoreBootTimeInMs: int, GroupPolicyBootTimeInMs: int, GroupPolicyLoginTimeInMs: int, CoreLoginTimeInMs: int, TotalBootTimeInMs: int, TotalLoginTimeInMs: int, IsFirstLogin: bool, IsFeatureUpdate: bool, OperatingSystemVersion: string, RestartCategory: string, RestartFaultBucket: string, IngestionTime: datetime, SourceSystem: string)

.alter table StartupPerformance policy retention ```{ "SoftDeletePeriod": "30.00:00:00", "Recoverability": "Disabled" }```

.create table AppReliability (AppName: string, AppDisplayName: string, AppPublisher: string, ActiveDeviceCount: int, AppCrashCount: int, AppHangCount: int, MeanTimeToFailureInMinutes: int, AppHealthScore: real, AppHealthStatus: string, IngestionTime: datetime, SourceSystem: string)

.alter table AppReliability policy retention ```{ "SoftDeletePeriod": "7.00:00:00", "Recoverability": "Disabled" }```

.create materialized-view AppReliability_Current on table AppReliability { AppReliability | summarize arg_max(IngestionTime, *) by AppName }

.create table SyncState (ExportType: string, RecordCount: int, StartTime: datetime, EndTime: datetime, DurationSeconds: real, Status: string, ErrorMessage: string, IngestionTime: datetime, SourceSystem: string)

.create-or-alter function NonCompliantDevices() { DeviceComplianceStates_Current | where Status == "noncompliant" | join kind=leftouter ManagedDevices_Current on DeviceId | project DeviceId, DeviceName = coalesce(DeviceName, DeviceName1), UserPrincipalName = coalesce(UserPrincipalName, UserPrincipalName1), UserDisplayName, PolicyName, FailedSettingCount, LastContact, OperatingSystem, OSVersion, LastSyncDateTime | order by FailedSettingCount desc }

.create-or-alter function ComplianceSummaryByPolicy() { DeviceComplianceStates_Current | summarize TotalDevices = count(), Compliant = countif(Status == "compliant"), NonCompliant = countif(Status == "noncompliant"), InGracePeriod = countif(Status == "inGracePeriod"), Unknown = countif(Status == "unknown"), NotApplicable = countif(Status == "notApplicable") by PolicyId, PolicyName | extend ComplianceRate = round(100.0 * Compliant / TotalDevices, 1) | order by NonCompliant desc }

.create-or-alter function PoorHealthDevices(threshold: real = 50.0) { DeviceScores_Current | where EndpointAnalyticsScore < threshold | join kind=leftouter ManagedDevices_Current on DeviceId | project DeviceId, DeviceName, UserPrincipalName, Model, HealthStatus, EndpointAnalyticsScore, StartupPerformanceScore, AppReliabilityScore, LastSyncDateTime | order by EndpointAnalyticsScore asc }

.create-or-alter function SlowStartupDevices(thresholdMs: int = 60000) { StartupPerformance | where TotalBootTimeInMs > thresholdMs | summarize AvgBootTimeMs = avg(TotalBootTimeInMs), MaxBootTimeMs = max(TotalBootTimeInMs), BootCount = count() by DeviceId | join kind=leftouter ManagedDevices_Current on DeviceId | project DeviceId, DeviceName, UserPrincipalName, AvgBootTimeMs = round(AvgBootTimeMs, 0), MaxBootTimeMs, BootCount, Model | order by AvgBootTimeMs desc }

.create-or-alter function ProblematicApps() { AppReliability_Current | where AppCrashCount > 0 or AppHangCount > 0 | extend TotalIssues = AppCrashCount + AppHangCount | project AppDisplayName, AppPublisher, ActiveDeviceCount, AppCrashCount, AppHangCount, TotalIssues, MeanTimeToFailureInMinutes, AppHealthScore | order by TotalIssues desc }

.create-or-alter function StaleDevices(daysInactive: int = 14) { ManagedDevices_Current | where LastSyncDateTime < ago(1d * daysInactive) | project DeviceId, DeviceName, UserPrincipalName, UserDisplayName, OperatingSystem, LastSyncDateTime, DaysSinceSync = datetime_diff('day', now(), LastSyncDateTime) | order by DaysSinceSync desc }

.create-or-alter function DeviceHealthOverview() { ManagedDevices_Current | summarize TotalDevices = count(), Compliant = countif(ComplianceState == "compliant"), NonCompliant = countif(ComplianceState == "noncompliant"), WindowsDevices = countif(OperatingSystem has "Windows"), iOSDevices = countif(OperatingSystem has "iOS"), AndroidDevices = countif(OperatingSystem has "Android"), macOSDevices = countif(OperatingSystem has "macOS"), EncryptedDevices = countif(IsEncrypted == true), ActiveLast7Days = countif(LastSyncDateTime > ago(7d)), ActiveLast30Days = countif(LastSyncDateTime > ago(30d)) | extend ComplianceRate = round(100.0 * Compliant / TotalDevices, 1), EncryptionRate = round(100.0 * EncryptedDevices / TotalDevices, 1) }

.create-or-alter function AlertNewNonCompliant() { DeviceComplianceStates | where IngestionTime > ago(6h) | where Status == "noncompliant" | join kind=anti ( DeviceComplianceStates | where IngestionTime between (ago(12h) .. ago(6h)) | where Status == "noncompliant" ) on DeviceId, PolicyId | join kind=leftouter ManagedDevices_Current on DeviceId | project DeviceId, DeviceName, UserPrincipalName, UserDisplayName, PolicyName, FailedSettingCount, DetectedAt = IngestionTime | order by DetectedAt desc }

.create-or-alter function AlertHealthScoreDrop(dropThreshold: real = 20.0) { DeviceScores | where IngestionTime > ago(1d) | summarize arg_max(IngestionTime, *) by DeviceId | join kind=inner ( DeviceScores | where IngestionTime between (ago(2d) .. ago(1d)) | summarize arg_max(IngestionTime, EndpointAnalyticsScore) by DeviceId | project DeviceId, PreviousScore = EndpointAnalyticsScore ) on DeviceId | extend ScoreDrop = PreviousScore - EndpointAnalyticsScore | where ScoreDrop > dropThreshold | project DeviceId, DeviceName, PreviousScore, CurrentScore = EndpointAnalyticsScore, ScoreDrop, HealthStatus | order by ScoreDrop desc }

param(
    [string]$ManagedIdentityPrincipalId,
    [string]$GraphAppId,
    [string]$DeviceMgmtReadAllRoleId,
    [string]$DeviceConfigReadAllRoleId,
    [string]$TenantId
)

$DeploymentScriptOutputs = @{}
$DeploymentScriptOutputs['status'] = 'starting'

Write-Host "====================================="
Write-Host "Graph API Permission Assignment"
Write-Host "====================================="
Write-Host "Function App Managed Identity: $ManagedIdentityPrincipalId"
Write-Host "Tenant ID: $TenantId"

# Get the Microsoft Graph Service Principal
try {
    $graphSp = Get-AzADServicePrincipal -ApplicationId $GraphAppId -ErrorAction Stop
    Write-Host "Found Microsoft Graph SP: $($graphSp.Id)"
} catch {
    Write-Warning "Could not find Microsoft Graph service principal. The deployer identity may not have sufficient permissions."
    Write-Warning "Error: $($_.Exception.Message)"
    Write-Host ""
    Write-Host "MANUAL STEP REQUIRED:"
    Write-Host "Run this in Azure Cloud Shell (PowerShell):"
    Write-Host '-------------------------------------------'
    Write-Host "\$graphId = (Get-AzADServicePrincipal -ApplicationId '00000003-0000-0000-c000-000000000000').Id"
    Write-Host "New-AzADServicePrincipalAppRoleAssignment -ServicePrincipalId '$ManagedIdentityPrincipalId' -ResourceId \$graphId -AppRoleId '$DeviceMgmtReadAllRoleId'"
    Write-Host "New-AzADServicePrincipalAppRoleAssignment -ServicePrincipalId '$ManagedIdentityPrincipalId' -ResourceId \$graphId -AppRoleId '$DeviceConfigReadAllRoleId'"
    Write-Host '-------------------------------------------'
    $DeploymentScriptOutputs['status'] = 'manual-required'
    $DeploymentScriptOutputs['permissionsGranted'] = $false
    exit 0
}

$successCount = 0
$failedPermissions = @()

# Grant DeviceManagementManagedDevices.Read.All
try {
    $existing = Get-AzADServicePrincipalAppRoleAssignment -ServicePrincipalId $ManagedIdentityPrincipalId -ErrorAction SilentlyContinue | Where-Object { $_.AppRoleId -eq $DeviceMgmtReadAllRoleId }
    if ($existing) {
        Write-Host "[OK] DeviceManagementManagedDevices.Read.All - Already assigned"
        $successCount++
    } else {
        New-AzADServicePrincipalAppRoleAssignment -ServicePrincipalId $ManagedIdentityPrincipalId -ResourceId $graphSp.Id -AppRoleId $DeviceMgmtReadAllRoleId -ErrorAction Stop | Out-Null
        Write-Host "[OK] DeviceManagementManagedDevices.Read.All - Granted"
        $successCount++
    }
} catch {
    if ($_.Exception.Message -like '*already exists*' -or $_.Exception.Message -like '*Permission being assigned already exists*') {
        Write-Host "[OK] DeviceManagementManagedDevices.Read.All - Already assigned"
        $successCount++
    } else {
        Write-Warning "[FAILED] DeviceManagementManagedDevices.Read.All: $($_.Exception.Message)"
        $failedPermissions += 'DeviceManagementManagedDevices.Read.All'
    }
}

# Grant DeviceManagementConfiguration.Read.All
try {
    $existing = Get-AzADServicePrincipalAppRoleAssignment -ServicePrincipalId $ManagedIdentityPrincipalId -ErrorAction SilentlyContinue | Where-Object { $_.AppRoleId -eq $DeviceConfigReadAllRoleId }
    if ($existing) {
        Write-Host "[OK] DeviceManagementConfiguration.Read.All - Already assigned"
        $successCount++
    } else {
        New-AzADServicePrincipalAppRoleAssignment -ServicePrincipalId $ManagedIdentityPrincipalId -ResourceId $graphSp.Id -AppRoleId $DeviceConfigReadAllRoleId -ErrorAction Stop | Out-Null
        Write-Host "[OK] DeviceManagementConfiguration.Read.All - Granted"
        $successCount++
    }
} catch {
    if ($_.Exception.Message -like '*already exists*' -or $_.Exception.Message -like '*Permission being assigned already exists*') {
        Write-Host "[OK] DeviceManagementConfiguration.Read.All - Already assigned"
        $successCount++
    } else {
        Write-Warning "[FAILED] DeviceManagementConfiguration.Read.All: $($_.Exception.Message)"
        $failedPermissions += 'DeviceManagementConfiguration.Read.All'
    }
}

Write-Host ""
Write-Host "====================================="
Write-Host "SUMMARY: $successCount/2 permissions configured"
Write-Host "====================================="

if ($failedPermissions.Count -gt 0) {
    Write-Host ""
    Write-Host "Some permissions failed. The deployer identity may need 'Application Administrator' role."
    Write-Host "Failed: $($failedPermissions -join ', ')"
    $DeploymentScriptOutputs['status'] = 'partial'
    $DeploymentScriptOutputs['failedPermissions'] = $failedPermissions
} else {
    $DeploymentScriptOutputs['status'] = 'success'
}

$DeploymentScriptOutputs['permissionsGranted'] = ($successCount -eq 2)
$DeploymentScriptOutputs['successCount'] = $successCount
